export function fieldToTsType(field: DMMF.Field): string {
  let tsType: string

  if (field.kind === 'scalar') {
    tsType = scalarTypeMap[field.type] ?? 'unknown'
  } else if (field.kind === 'enum' || field.kind === 'object') {
    tsType = field.type
  } else {
    tsType = 'unknown'
  }

  if (field.isList) {
    return `${tsType}[]`
  }
  if (!field.isRequired) {
    return `${tsType} | null`
  }
  return tsType
}

