  const idField = model.fields.find((f) => f.isId)
  if (!idField) return 'string'
  // Force required/non-list for the ID type used in method signatures
  return fieldToTsType({ ...idField, isRequired: true, isList: false })
}

/**
 * Returns a union string literal type of fields excluded from create/update
 * payloads — generated IDs, auto-timestamps, and read-only foreign keys.
 */
function getAutoManagedFieldsUnion(model: DMMF.Model): string {
  const names = model.fields
    .filter((f) => f.kind === 'scalar' && (f.isId || f.isReadOnly || f.isGenerated || f.isUpdatedAt))
    .map((f) => `'${f.name}'`)
  return names.length > 0 ? names.join(' | ') : 'never'
}

/**
 * Generates a TypeScript interface for the scalar and enum fields of a model.
 * Relation fields are intentionally omitted — they belong to separate interfaces
 * when relation payloads are needed.
 */
export function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => {
      const optional = !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${fieldToTsType(f)}`
    })

  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generates a typed REST client object with five CRUD methods for a model.
 * The client reads the base URL from the BASE_URL constant defined at the top
 * of the generated file.
 */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const lowerName = `${name.charAt(0).toLowerCase()}${name.slice(1)}`
  const idType = getIdType(model)
  const autoFields = getAutoManagedFieldsUnion(model)
  const createType = `Omit<${name}, ${autoFields}>`
  const updateType = `Partial<Omit<${name}, ${autoFields}>>`

