  } else if (field.kind === 'enum' || field.kind === 'object') {
    tsType = field.type
  } else {
    tsType = 'unknown'
  }

  if (field.isList) {
    return `${tsType}[]`
  }
  if (!field.isRequired) {
    return `${tsType} | null`
  }
  return tsType
}

function getIdType(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (!idField) return 'string'
  // Force required/non-list for the ID type used in method signatures
  return fieldToTsType({ ...idField, isRequired: true, isList: false })
}

/**
 * Returns a union string literal type of fields excluded from create/update
 * payloads — generated IDs, auto-timestamps, and read-only foreign keys.
 */
function getAutoManagedFieldsUnion(model: DMMF.Model): string {
  const names = model.fields
    .filter((f) => f.kind === 'scalar' && (f.isId || f.isReadOnly || f.isGenerated || f.isUpdatedAt))
    .map((f) => `'${f.name}'`)
  return names.length > 0 ? names.join(' | ') : 'never'
}

/**
 * Generates a TypeScript interface for the scalar and enum fields of a model.
 * Relation fields are intentionally omitted — they belong to separate interfaces
 * when relation payloads are needed.
 */
export function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => {
      const optional = !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${fieldToTsType(f)}`
    })

  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generates a typed REST client object with five CRUD methods for a model.
 * The client reads the base URL from the BASE_URL constant defined at the top
 * of the generated file.
 */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const lowerName = `${name.charAt(0).toLowerCase()}${name.slice(1)}`
  const idType = getIdType(model)
  const autoFields = getAutoManagedFieldsUnion(model)
  const createType = `Omit<${name}, ${autoFields}>`
  const updateType = `Partial<Omit<${name}, ${autoFields}>>`

  return `export const ${lowerName}Client = {
  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
    const query = new URLSearchParams()
    if (params?.skip !== undefined) query.set('skip', String(params.skip))
    if (params?.take !== undefined) query.set('take', String(params.take))
    const response = await fetch(\`\${BASE_URL}/${lowerName}?\${query}\`)
    return response.json() as Promise<${name}[]>
  },

  async findUnique(id: ${idType}): Promise<${name} | null> {
    const response = await fetch(\`\${BASE_URL}/${lowerName}/\${id}\`)
    if (response.status === 404) return null
    return response.json() as Promise<${name}>
  },

  async create(data: ${createType}): Promise<${name}> {
    const response = await fetch(\`\${BASE_URL}/${lowerName}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return response.json() as Promise<${name}>
  },

  async update(id: ${idType}, data: ${updateType}): Promise<${name}> {
    const response = await fetch(\`\${BASE_URL}/${lowerName}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return response.json() as Promise<${name}>
  },

  async delete(id: ${idType}): Promise<${name}> {
    const response = await fetch(\`\${BASE_URL}/${lowerName}/\${id}\`, {
      method: 'DELETE',
    })
    return response.json() as Promise<${name}>
  },
}`
}
```

---

### 6. `packages/generator-rest-client/src/generator.ts`

Core generation logic: reads DMMF, assembles output, writes file.

```typescript
import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateModelClient, generateModelInterface } from './template'

/**
 * Generates a typed REST API client from the Prisma DMMF and writes it to
 * `rest-client.ts` inside the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error(
      'The @prisma/generator-rest-client generator requires an `output` path in the generator block.',
    )
  }

  fs.mkdirSync(outputDir, { recursive: true })

  const parts: string[] = [
    '// This file was auto-generated by @prisma/generator-rest-client.',
    '// Do not edit manually.',
    '',
    '// Set REST_API_BASE_URL in your environment or replace this constant.',
    'const BASE_URL = process.env.REST_API_BASE_URL ?? ""',
    '',
  ]

  for (const model of options.dmmf.datamodel.models) {
    parts.push(generateModelInterface(model))
    parts.push('')
    parts.push(generateModelClient(model))
    parts.push('')
  }

  const outputPath = path.join(outputDir, 'rest-client.ts')
  fs.writeFileSync(outputPath, parts.join('\n'))
}
```

---

### 7. `packages/generator-rest-client/src/index.ts`

Entry point that registers the generator with the Prisma CLI protocol.

```typescript
import type { GeneratorConfig, GeneratorManifest } from '@prisma/generator'
import { generatorHandler } from '@prisma/generator-helper'

import { generate } from './generator'

generatorHandler({
  onManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      prettyName: 'REST API Client',
      defaultOutput: './generated/rest-client',
      requiresEngines: [],
    }
  },

  async onGenerate(options) {
    await generate(options)
  },
})
```

`generatorHandler` wires up stdin readline → `onManifest` / `onGenerate`, and writes JSON-RPC responses to stderr (confirmed in `packages/generator-helper/src/generatorHandler.ts`).

---

## File to Modify

### `tsconfig.build.bundle.json` (root)

Add one entry to `compilerOptions.paths` alongside the other `@prisma/*` packages:

```json
"@prisma/generator-rest-client": ["./packages/generator-rest-client/src"]
```

Insert it after the existing `"@prisma/generator-helper"` line, preserving alphabetical-ish ordering.

---

## Architecture Notes

| Concern | Decision |
|---|---|
| Generator protocol | Use `generatorHandler` from `@prisma/generator-helper` — the simplest correct approach for a standalone generator |
| CLI invocability | `bin` field + shebang banner on CJS build |
| Relation fields in interfaces | Excluded from base interface (avoids circular type references without a full Payload/Select system) |
| Auto-managed fields | `Omit<Model, 'id' \| 'createdAt' \| ...>` for create/update payload types — derived from `isId`, `isReadOnly`, `isGenerated`, `isUpdatedAt` flags in DMMF |
| File output | Single `rest-client.ts` written with `fs.writeFileSync` — same approach used by simpler generators |
| No barrel files | `index.ts` imports directly from `./generator`, `generator.ts` imports from `./template` |

---

## Verification

1. **Build the new package**:
   ```sh
   pnpm --filter @prisma/generator-rest-client build
   ```
   Expect: `dist/index.js`, `dist/index.mjs`, `dist/index.d.ts` created without errors.

2. **Check shebang**:
   ```sh
   head -1 packages/generator-rest-client/dist/index.js
   # Should print: #!/usr/bin/env node
   ```

3. **Integration smoke test** — create a minimal Prisma schema in a temp dir:
   ```prisma
   // schema.prisma
   generator restClient {
     provider = "prisma-generator-rest-client"
     output   = "./generated/rest-client"
   }
   ```
   Run:
   ```sh
   node packages/generator-rest-client/dist/index.js
   ```
   (with appropriate JSON-RPC on stdin, or via `prisma generate` if the binary is on PATH)

4. **Type-check the generated output**: The produced `rest-client.ts` should compile without errors when run through `tsc --noEmit`.

5. **Root build** (optional, ensures dependency order is correct):
   ```sh
   pnpm build
   ```

