import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent.
 */
function scalarToTsType(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      // ISO 8601 string is the natural representation across JSON boundaries.
      return 'string'
    case 'Json':
      return 'unknown'
    case 'BigInt':
      return 'bigint'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}

/**
 * Returns the TypeScript type for a scalar or enum DMMF field.
 * Relation (`object`) and `unsupported` fields must not be passed here.
 */
export function fieldToTsType(field: Field): string {
  let base: string
  if (field.kind === 'enum') {
    base = field.type
  } else {
    base = scalarToTsType(field.type)
  }

  if (field.isList) {
    base = `${base}[]`
  }

  return field.isRequired ? base : `${base} | null`
}

/** Returns only the scalar and enum fields of a model (no relations, no unsupported). */
function scalarFields(model: Model): readonly Field[] {
  return model.fields.filter((f) => f.kind !== 'object' && f.kind !== 'unsupported')
}

/**
 * Returns the names of fields that are automatically managed by the database and
 * should therefore be excluded from create/update write payloads.
 */
function autoManagedFieldNames(model: Model): string[] {
  return scalarFields(model)
    .filter((f) => (f.isId && f.hasDefaultValue) || !!f.isGenerated || !!f.isUpdatedAt || f.isReadOnly)
    .map((f) => f.name)
}

/** Generates a TypeScript string-union type alias for a Prisma enum. */
export function generateEnumType(prismaEnum: DatamodelEnum): string {
  const members = prismaEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${prismaEnum.name} = ${members}`
}

/** Generates a TypeScript interface representing a model record as returned by the API. */
export function generateModelInterface(model: Model): string {
  const fields = scalarFields(model)
  const lines = fields.map((f) => `  ${f.name}: ${fieldToTsType(f)}`)
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/** Generates the typed REST client class for a single model with all five CRUD methods. */
export function generateModelClient(model: Model): string {
  const { name } = model
  const omitted = autoManagedFieldNames(model)
  const writeBase =
    omitted.length > 0 ? `Omit<${name}, ${omitted.map((n) => `'${n}'`).join(' | ')}>` : name
  const route = name.toLowerCase()

  return `export class ${name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
    const query = params ? '?' + new URLSearchParams(params as Record<string, string>).toString() : ''
    const res = await fetch(\`\${this.baseUrl}/${route}\${query}\`)
    if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(id: string | number): Promise<${name} | null> {
    const res = await fetch(\`\${this.baseUrl}/${route}/\${id}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async create(data: ${writeBase}): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${route}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async update(id: string | number, data: Partial<${writeBase}>): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${route}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async delete(id: string | number): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${route}/\${id}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${name} failed: \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }
}`
}

/** Generates the root client that composes all per-model clients. */
function generateRootClient(models: readonly Model[]): string {
  const fields = models.map((m) => `  readonly ${m.name.toLowerCase()}: ${m.name}Client`).join('\n')
  const assignments = models
    .map((m) => `    this.${m.name.toLowerCase()} = new ${m.name}Client(baseUrl)`)
    .join('\n')

  return `export class RestClient {
${fields}

  constructor(baseUrl: string) {
${assignments}
  }
}`
}

/** Assembles the complete `rest-client.ts` file content from the provided DMMF data. */
export function generateRestClientFile(
  models: readonly Model[],
  enums: readonly DatamodelEnum[],
): string {
  const sections: string[] = [
    '// Auto-generated by @prisma/generator-rest-client. Do not edit.',
    '',
  ]

  if (enums.length > 0) {
    sections.push('// Enums', ...enums.map(generateEnumType), '')
  }

  if (models.length > 0) {
    sections.push('// Model interfaces', ...models.map(generateModelInterface), '')
    sections.push('// REST client classes', ...models.map(generateModelClient), '')
    sections.push(generateRootClient(models))
  }

  return sections.join('\n')
}

