import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { generateRestClientFile } from './template'

/**
 * Main generation entry point.
 *
 * Reads the DMMF from `options`, assembles the REST client source, and writes
 * `rest-client.ts` into the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error(
      'Output directory is required. Set the `output` field in the `generator restClient` block of your Prisma schema.',
    )
  }

  const { models, enums } = options.dmmf.datamodel

  fs.mkdirSync(outputDir, { recursive: true })

  const content = generateRestClientFile(models, enums)
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

